// src/pages/LoginPage.js

import React, { useState } from "react";
import { auth, db } from "../firebaseConfig"; // Correct import
import { signInWithEmailAndPassword } from "firebase/auth";
import { useAuth } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";
import { doc, getDoc } from "firebase/firestore";

const LoginPage = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const { user } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      const userDoc = await getDoc(doc(db, "users", user.uid));
      if (userDoc.exists()) {
        const role = userDoc.data().role;
        if (role === "student") {
          navigate("/student-landing"); // Redirect to student landing page
        } else if (role === "professor") {
          navigate("/professor-landing"); // Redirect to professor landing page
        } else if (role === "secretary") {
          navigate("/secretary-landing"); // Redirect to secretary landing page
        } else if (role === "admin") {
          navigate("/admin-landing"); // Redirect to admin landing page
        }
      }
    } catch (error) {
      console.error("Error logging in:", error.message);
    }
  };

  return (
    <form onSubmit={handleLogin}>
      <input type="email" placeholder="Email" onChange={(e) => setEmail(e.target.value)} required />
      <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} required />
      <button type="submit">Login</button>
    </form>
  );
};

export default LoginPage;
